#include "hx711_block.h"
static HX711 scale;
static float _weight=0;
static unsigned long _last=0;
void hx711_setup(){
  scale.begin(4,5);
  scale.set_scale(2280.0);
  scale.tare();
  Serial.println("[hx711] OK, tared");
}
void hx711_loop(){
  if(millis()-_last<500)return;
  _last=millis();
  if(scale.is_ready()){_weight=scale.get_units(5);Serial.printf("[hx711] %.1fg\n",_weight);}
}
float hx711_get_weight(){return _weight;}
void hx711_tare(){scale.tare();}
